import Foundation
import XCTest

/// Shared golden-byte fixtures and hex helpers for the `NOFS` OP-feed sidecar
/// decoder tests (ADR-0038 Stage T4).
///
/// The B1 golden hex (`crates/nmp-nip01/tests/fixtures/op_feed_{populated,empty}_v1.fb.hex`,
/// produced by `nmp_nip01::encode_op_feed_snapshot`) is embedded inline so the
/// tests need no bundle-resource wiring or simulator. This single source is
/// shared by `OpFeedDecoderTests` (parity/structure) and
/// `OpFeedRepostDecoderTests` (D0 typed repost signal) so the 553-char hex is
/// never duplicated.
enum OpFeedTestFixtures {

    /// 32-byte hex id from a single byte, mirroring the Rust fixture's
    /// `hex32(byte)` helper (`"03"` -> `"0303…03"`, 64 chars).
    static func hex32(_ byte: UInt8) -> String {
        String(format: "%02x", byte).opFeedRepeated(32)
    }

    /// Decode a (whitespace-tolerant) hex string into raw bytes, failing the
    /// calling test on malformed input.
    static func data(fromHex hex: String) -> Data {
        let compact = hex.unicodeScalars.filter { !CharacterSet.whitespacesAndNewlines.contains($0) }
        let chars = Array(String(String.UnicodeScalarView(compact)))
        XCTAssertEqual(chars.count % 2, 0, "hex fixture must contain whole bytes")
        var bytes = [UInt8]()
        bytes.reserveCapacity(chars.count / 2)
        var index = chars.startIndex
        while index < chars.endIndex {
            let pair = String(chars[index ... chars.index(after: index)])
            guard let byte = UInt8(pair, radix: 16) else {
                XCTFail("invalid hex pair \(pair)")
                return Data()
            }
            bytes.append(byte)
            index = chars.index(index, offsetBy: 2)
        }
        return Data(bytes)
    }

    // ── Golden bytes (B1 fixtures, verbatim) ─────────────────────────────────

    static let emptyHex =
        "100000004e4f46530800080000000400080000000400000000000000"

    static let populatedHex =
        ""
}

private extension String {
    /// Repeat the receiver `count` times (`"ab".opFeedRepeated(2) == "abab"`).
    func opFeedRepeated(_ count: Int) -> String {
        String(repeating: self, count: count)
    }
}
